import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import { collection, getDocs, doc, updateDoc, deleteDoc, addDoc, query, where, onSnapshot } from 'firebase/firestore';
import { 
  LayoutDashboard, LogOut, CheckCircle, XCircle, Trash2, Clock, LayoutGrid,
  ShieldAlert, Eye, X, ExternalLink, Image as ImageIcon, Users, UserPlus, Key, Mail, Shield, Menu, Utensils, Package, RefreshCcw, Home
} from 'lucide-react';

function AdminDashboard({ onLogout, onNavigate }) {
  // --- CORE STATE ---
  const [activeTab, setActiveTab] = useState('dashboard');
  const [projects, setProjects] = useState([]);
  const [usersList, setUsersList] = useState([]); 
  const [userMap, setUserMap] = useState({});
  const [loading, setLoading] = useState(true);
  
  // --- CANTEEN STATE ---
  const [canteenOrders, setCanteenOrders] = useState([]);
  const [canteenInventory, setCanteenInventory] = useState([]);
  
  // --- UI STATE ---
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  
  // --- MODAL STATES ---
  const [reviewProject, setReviewProject] = useState(null);
  const [selectedUser, setSelectedUser] = useState(null);
  const [showAddUser, setShowAddUser] = useState(false);
  const [newUser, setNewUser] = useState({ name: '', username: '', password: '', role: 'Student' });

  // --- 🔄 FETCH DATA ---
  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const [projectsSnapshot, usersSnapshot] = await Promise.all([
        getDocs(collection(db, "projects")),
        getDocs(collection(db, "users"))
      ]);

      // Process Users
      const usersData = usersSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setUsersList(usersData);

      const usersDictionary = {};
      usersData.forEach(userData => {
        const actualName = userData.fullName || userData.Name || userData.name || "Unknown User";
        if (userData.username) usersDictionary[userData.username] = actualName;
      });
      setUserMap(usersDictionary);

      // Process Projects
      const projectsList = projectsSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      projectsList.sort((a, b) => (a.status === 'Pending' ? -1 : 1));
      setProjects(projectsList);
      
    } catch (error) {
      console.error("Error fetching dashboard data:", error);
    } finally {
      setLoading(false);
    }
  };

  // --- 🍔 CANTEEN REAL-TIME SYNC ---
  useEffect(() => {
    fetchDashboardData();

    // Sync Canteen Orders
    const unsubOrders = onSnapshot(collection(db, "orders"), (snap) => {
      setCanteenOrders(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });

    // Sync Canteen Inventory
    const unsubInv = onSnapshot(collection(db, "canteen_items"), (snap) => {
      setCanteenInventory(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });

    return () => { unsubOrders(); unsubInv(); };
  }, []);

  // --- ⚡ ACTIONS ---
  const updateStatus = async (projectId, newStatus) => {
    try {
      await updateDoc(doc(db, "projects", projectId), { status: newStatus });
      setProjects(projects.map(p => p.id === projectId ? { ...p, status: newStatus } : p));
      if (reviewProject && reviewProject.id === projectId) setReviewProject(null);
    } catch (error) { console.error(error); }
  };

  const handleDeleteProject = async (projectId) => {
    if (window.confirm("Delete project permanently?")) {
      await deleteDoc(doc(db, "projects", projectId));
      setProjects(projects.filter(p => p.id !== projectId));
    }
  };

  const completeCanteenOrder = async (id) => {
    if (window.confirm("Mark order as served?")) {
      await deleteDoc(doc(db, "orders", id));
    }
  };

  const updateCanteenStock = async (id, newStock) => {
    await updateDoc(doc(db, "canteen_items", id), { stock: parseInt(newStock) });
  };

  const handleAddUser = async (e) => {
    e.preventDefault();
    try {
      const q = query(collection(db, "users"), where("username", "==", newUser.username));
      const snapshot = await getDocs(q);
      if (!snapshot.empty) return alert("User already exists!");

      await addDoc(collection(db, "users"), {
        fullName: newUser.name, 
        username: newUser.username,
        password: newUser.password,
        role: newUser.role
      });
      setShowAddUser(false);
      fetchDashboardData();
      alert("User added!");
    } catch (error) { console.error(error); }
  };
  
  const handleDeleteUser = async (userId) => {
     if (window.confirm("Delete this user?")) {
        await deleteDoc(doc(db, "users", userId));
        setUsersList(usersList.filter(u => u.id !== userId));
     }
  };

  const getUserProjects = (targetUser) => {
    return projects.filter(p => p.authorUsername === targetUser.username || p.authorName === (targetUser.fullName || targetUser.name));
  };

  return (
    <div className="flex min-h-screen bg-[#0a0a0a] text-gray-100 font-sans overflow-hidden relative">
      
      {/* --- SIDEBAR --- */}
      <div className={`fixed inset-y-0 left-0 z-40 w-64 bg-[#050505] border-r border-white/10 flex flex-col justify-between transform transition-transform duration-300 md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:static`}>
        <div>
          <div className="p-6 border-b border-white/10 flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg"><ShieldAlert className="w-5 h-5 text-white" /></div>
            <div><h1 className="text-lg font-bold text-white">Admin Panel</h1><p className="text-[10px] text-gray-400 uppercase">Control Center</p></div>
          </div>
          
          <nav className="p-4 space-y-2">
            <button onClick={() => setActiveTab('dashboard')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'dashboard' ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 'text-gray-400 hover:bg-white/5'}`}><LayoutDashboard className="w-5 h-5" /> Projects</button>
            <button onClick={() => setActiveTab('users')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'users' ? 'bg-purple-600/20 text-purple-400 border border-purple-500/30' : 'text-gray-400 hover:bg-white/5'}`}><Users className="w-5 h-5" /> Manage Users</button>
            <button onClick={() => setActiveTab('canteen')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'canteen' ? 'bg-orange-600/20 text-orange-400 border border-orange-500/30' : 'text-gray-400 hover:bg-white/5'}`}><Utensils className="w-5 h-5" /> Canteen Control</button>
            <div className="pt-4 border-t border-white/5 mt-4">
               <button onClick={() => onNavigate('home')} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium text-gray-400 hover:bg-white/5"><Home className="w-5 h-5" /> Student View</button>
            </div>
          </nav>
        </div>
        <div className="p-4 border-t border-white/10"><button onClick={onLogout} className="w-full flex items-center gap-3 text-red-400 hover:bg-red-500/10 px-4 py-3 rounded-xl font-medium"><LogOut className="w-5 h-5" /> Logout</button></div>
      </div>

      {/* --- MAIN CONTENT --- */}
      <div className="flex-1 h-screen overflow-y-auto p-4 md:p-8 relative custom-scrollbar">
        <div className="max-w-6xl mx-auto">
          
          {/* TAB 1: PROJECT DASHBOARD */}
          {activeTab === 'dashboard' && (
            <div className="animate-fade-in-up">
              <h2 className="text-3xl font-extrabold text-white mb-8">Project Repository</h2>
              
              {/* Stats */}
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 mb-10">
                <div className="bg-white/5 border border-white/10 p-6 rounded-2xl"><span className="text-gray-400 text-xs font-bold uppercase block mb-1">Total Submissions</span><span className="text-4xl font-black">{projects.length}</span></div>
                <div className="bg-white/5 border border-white/10 p-6 rounded-2xl"><span className="text-yellow-400 text-xs font-bold uppercase block mb-1">Pending Review</span><span className="text-4xl font-black">{projects.filter(p => p.status === 'Pending').length}</span></div>
                <div className="bg-white/5 border border-white/10 p-6 rounded-2xl"><span className="text-green-400 text-xs font-bold uppercase block mb-1">Approved Projects</span><span className="text-4xl font-black">{projects.filter(p => p.status === 'Approved').length}</span></div>
              </div>

              {/* RESTORED PROJECTS TABLE */}
              <div className="bg-white/5 border border-white/10 rounded-[2rem] overflow-hidden">
                <table className="w-full text-left border-collapse min-w-[600px]">
                  <thead>
                    <tr className="bg-black/20 text-xs text-gray-400 uppercase tracking-widest">
                      <th className="p-5 font-semibold">Project Name</th>
                      <th className="p-5 font-semibold">Author</th>
                      <th className="p-5 font-semibold">Status</th>
                      <th className="p-5 font-semibold text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-white/5">
                    {projects.map((project) => (
                      <tr key={project.id} className="hover:bg-white/5 transition-colors">
                        <td className="p-5"><p className="font-bold">{project.title}</p><span className="text-[10px] bg-indigo-500/10 text-indigo-400 px-2 py-1 rounded uppercase">{project.category}</span></td>
                        <td className="p-5 text-sm text-gray-300">{project.authorName || 'Unknown'}</td>
                        <td className="p-5">
                            {project.status === 'Approved' && <span className="text-green-400 text-xs font-bold flex items-center gap-1"><CheckCircle className="w-3 h-3"/> Approved</span>}
                            {project.status === 'Pending' && <span className="text-yellow-400 text-xs font-bold flex items-center gap-1"><Clock className="w-3 h-3"/> Pending</span>}
                            {project.status === 'Rejected' && <span className="text-red-400 text-xs font-bold flex items-center gap-1"><XCircle className="w-3 h-3"/> Rejected</span>}
                        </td>
                        <td className="p-5 text-right flex justify-end gap-2">
                            <button onClick={() => setReviewProject(project)} className="p-2 bg-blue-500/10 text-blue-400 rounded-lg hover:bg-blue-500 hover:text-white"><Eye className="w-4 h-4"/></button>
                            {project.status !== 'Approved' && <button onClick={() => updateStatus(project.id, 'Approved')} className="p-2 bg-green-500/10 text-green-400 rounded-lg hover:bg-green-500 hover:text-white"><CheckCircle className="w-4 h-4"/></button>}
                            <button onClick={() => handleDeleteProject(project.id)} className="p-2 bg-red-500/10 text-red-400 rounded-lg hover:bg-red-500 hover:text-white"><Trash2 className="w-4 h-4"/></button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* TAB 2: MANAGE USERS */}
          {activeTab === 'users' && (
            <div className="animate-fade-in-up">
              <div className="flex justify-between items-center mb-8">
                <h2 className="text-3xl font-extrabold text-white">System Users</h2>
                <button onClick={() => setShowAddUser(true)} className="bg-purple-600 hover:bg-purple-500 text-white px-6 py-3 rounded-xl font-bold shadow-lg flex items-center gap-2"><UserPlus className="w-5 h-5"/> Add User</button>
              </div>

              {/* RESTORED USERS TABLE */}
              <div className="bg-white/5 border border-white/10 rounded-[2rem] overflow-hidden">
                <table className="w-full text-left border-collapse min-w-[600px]">
                   <thead>
                     <tr className="bg-black/20 text-xs text-gray-400 uppercase tracking-widest">
                       <th className="p-5 font-semibold">User</th>
                       <th className="p-5 font-semibold">Username/ID</th>
                       <th className="p-5 font-semibold">Role</th>
                       <th className="p-5 font-semibold text-right">Actions</th>
                     </tr>
                   </thead>
                   <tbody className="divide-y divide-white/5">
                     {usersList.map(user => (
                       <tr key={user.id} className="hover:bg-white/5 transition-colors">
                         <td className="p-5 font-bold text-white flex items-center gap-3">
                           <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-purple-500 to-indigo-500 flex items-center justify-center text-[10px]">{user.fullName?.charAt(0) || 'U'}</div>
                           {user.fullName || user.name || 'Unknown'}
                         </td>
                         <td className="p-5 text-sm text-gray-400 font-mono">{user.username}</td>
                         <td className="p-5"><span className="text-xs font-bold uppercase bg-white/5 border border-white/10 px-2 py-1 rounded">{user.role || 'Student'}</span></td>
                         <td className="p-5 text-right flex justify-end gap-2">
                            <button onClick={() => setSelectedUser(user)} className="p-2 bg-purple-500/10 text-purple-400 rounded-lg hover:bg-purple-500 hover:text-white"><Eye className="w-4 h-4"/></button>
                            <button onClick={() => handleDeleteUser(user.id)} className="p-2 bg-red-500/10 text-red-400 rounded-lg hover:bg-red-500 hover:text-white"><Trash2 className="w-4 h-4"/></button>
                         </td>
                       </tr>
                     ))}
                   </tbody>
                </table>
              </div>
            </div>
          )}

          {/* TAB 3: CANTEEN TAB */}
          {activeTab === 'canteen' && (
            <div className="animate-fade-in-up">
              <h2 className="text-3xl font-extrabold text-white mb-8">Canteen Operations</h2>
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                
                {/* Active Orders */}
                <div className="bg-white/5 border border-white/10 rounded-[2rem] p-8 backdrop-blur-md">
                   <h3 className="text-xl font-bold mb-6 flex items-center gap-2 text-orange-400"><Package className="w-5 h-5" /> Live Orders</h3>
                   <div className="space-y-4 max-h-[400px] overflow-y-auto">
                     {canteenOrders.length > 0 ? canteenOrders.map(order => (
                       <div key={order.id} className="bg-black/40 p-5 rounded-2xl border border-white/5 flex justify-between items-center group">
                          <div>
                            <p className="text-[10px] text-gray-500 font-black uppercase">Token: {order.id.slice(-6).toUpperCase()}</p>
                            <p className="text-lg font-bold text-white">{order.itemName}</p>
                            <p className="text-xs text-indigo-400">Customer: {order.customerName}</p>
                          </div>
                          <button onClick={() => completeCanteenOrder(order.id)} className="p-3 bg-green-500/20 text-green-500 hover:bg-green-500 hover:text-white rounded-xl transition-all"><CheckCircle className="w-6 h-6" /></button>
                       </div>
                     )) : <p className="text-gray-600 italic">No active orders.</p>}
                   </div>
                </div>

                {/* Stock Management */}
                <div className="bg-white/5 border border-white/10 rounded-[2rem] p-8 backdrop-blur-md">
                   <h3 className="text-xl font-bold mb-6 flex items-center gap-2 text-indigo-400"><RefreshCcw className="w-5 h-5" /> Stock Management</h3>
                   <div className="space-y-4 max-h-[400px] overflow-y-auto">
                     {canteenInventory.map(item => (
                       <div key={item.id} className="bg-black/40 p-5 rounded-2xl border border-white/5 flex justify-between items-center">
                          <div className="flex items-center gap-3">
                            <span className="text-2xl">{item.icon}</span>
                            <div><p className="font-bold text-white">{item.name}</p><p className="text-xs text-gray-500">Price: ₹{item.price}</p></div>
                          </div>
                          <div className="flex items-center gap-2">
                             <input 
                               type="number" 
                               defaultValue={item.stock}
                               onBlur={(e) => updateCanteenStock(item.id, e.target.value)}
                               className="w-16 bg-white/5 border border-white/10 rounded-lg p-2 text-center text-sm focus:border-indigo-500 outline-none"
                             />
                             <span className="text-[10px] text-gray-500 font-bold uppercase">Qty</span>
                          </div>
                       </div>
                     ))}
                   </div>
                </div>

              </div>
            </div>
          )}

        </div>
      </div>

      {/* --- ADD USER MODAL --- */}
      {showAddUser && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={() => setShowAddUser(false)}></div>
          <div className="relative bg-[#0a0a0a] border border-white/10 rounded-[2rem] p-8 w-full max-w-md">
            <h2 className="text-2xl font-bold mb-6 text-white">Add New User</h2>
            <form onSubmit={handleAddUser} className="space-y-4">
              <input type="text" placeholder="Full Name" className="w-full bg-black/50 border border-white/10 rounded-xl p-3 text-white" value={newUser.name} onChange={e => setNewUser({...newUser, name: e.target.value})} />
              <input type="text" placeholder="Username" className="w-full bg-black/50 border border-white/10 rounded-xl p-3 text-white" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} />
              <input type="password" placeholder="Password" className="w-full bg-black/50 border border-white/10 rounded-xl p-3 text-white" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} />
              <select className="w-full bg-black/50 border border-white/10 rounded-xl p-3 text-white" value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value})}>
                <option value="Student">Student</option>
                <option value="Admin">Admin</option>
              </select>
              <button type="submit" className="w-full bg-purple-600 text-white py-3 rounded-xl font-bold mt-4">Create Account</button>
            </form>
          </div>
        </div>
      )}

      {/* --- REVIEW PROJECT MODAL --- */}
      {reviewProject && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
           <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={() => setReviewProject(null)}></div>
           <div className="relative bg-[#0a0a0a] border border-white/10 rounded-[2rem] p-8 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
              <h2 className="text-2xl font-bold mb-4">{reviewProject.title}</h2>
              <p className="text-gray-400 mb-6">{reviewProject.description}</p>
              <div className="flex gap-4">
                <button onClick={() => updateStatus(reviewProject.id, 'Approved')} className="flex-1 bg-green-500 text-white py-3 rounded-xl font-bold">Approve</button>
                <button onClick={() => updateStatus(reviewProject.id, 'Rejected')} className="flex-1 bg-red-500/20 text-red-500 py-3 rounded-xl font-bold">Reject</button>
              </div>
           </div>
        </div>
      )}

    </div>
  );
}

export default AdminDashboard;
